import React, { useState, useEffect, useRef, useCallback } from 'react';
import { db, auth, signInAnon } from './firebase';
import { ref, onValue, set, get } from 'firebase/database';
import './App.css';

const PASSWORD = "Nirav is Lyla's absolute favorite";
const INITIAL_SECONDS = 30 * 3600; // 30 hours

// ─────────────────────────────────────────────────────────────────────────────
// Timer architecture (fixes multi-tab multiplication):
//
//  Firebase /timerState stores:
//    { secondsAtStart, startedAt (unix ms), running }
//
//  NO tab ever writes the ticking value back to Firebase.
//  Every tab independently computes:
//    displayed = secondsAtStart - (Date.now() - startedAt) / 1000
//
//  Only Start and Pause write to Firebase. 100 tabs = 1 timer.
//
//  Firebase /pendingActivity stores the in-progress activity data as a
//  cross-tab lock. While it exists, other tabs cannot start the timer.
// ─────────────────────────────────────────────────────────────────────────────

const formatTime = (totalSeconds) => {
  const neg = totalSeconds < 0;
  const abs = Math.abs(Math.round(totalSeconds));
  const h = Math.floor(abs / 3600).toString().padStart(2, '0');
  const m = Math.floor((abs % 3600) / 60).toString().padStart(2, '0');
  const s = (abs % 60).toString().padStart(2, '0');
  return { neg, str: `${h}:${m}:${s}` };
};

const nowLabel = () => {
  const d = new Date();
  return {
    date: d.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' }),
    time: d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
  };
};

const uid = () => Math.random().toString(36).slice(2, 10) + Date.now().toString(36);

// ── Password Gate Modal ───────────────────────────────────────────────────────
function PasswordModal({ onConfirm, onCancel }) {
  const [pw, setPw] = useState('');
  const [wrong, setWrong] = useState(false);

  const check = () => {
    if (pw === PASSWORD) { onConfirm(); }
    else { setWrong(true); setPw(''); }
  };

  return (
    <div className="overlay">
      <div className="modal password-modal">
        <h2>Are you sure?</h2>
        <label className="field-label">Password</label>
        <input
          type="password"
          value={pw}
          onChange={e => { setPw(e.target.value); setWrong(false); }}
          onKeyDown={e => e.key === 'Enter' && check()}
          className={`text-input${wrong ? ' input-error' : ''}`}
          placeholder="Enter password…"
          autoFocus
        />
        {wrong && <p className="error-msg">Incorrect password. Try again.</p>}
        <div className="btn-row">
          <button className="btn btn-ghost" onClick={onCancel}>Cancel</button>
          <button className="btn btn-primary" onClick={check}>Confirm</button>
        </div>
      </div>
    </div>
  );
}

// ── Activity Blocked Modal ────────────────────────────────────────────────────
function ActivityBlockedModal({ onClose, onOverride }) {
  const [showPassword, setShowPassword] = useState(false);

  if (showPassword) {
    return (
      <PasswordModal
        onConfirm={onOverride}
        onCancel={() => setShowPassword(false)}
      />
    );
  }

  return (
    <div className="overlay">
      <div className="modal small-modal">
        <h2>Can't start timer.</h2>
        <p className="sub-text">Activity being created.</p>
        <div className="btn-row">
          <button className="btn btn-ghost" onClick={onClose}>Close</button>
          <button className="btn btn-warn" onClick={() => setShowPassword(true)}>Override</button>
        </div>
      </div>
    </div>
  );
}

// ── Description Modal ─────────────────────────────────────────────────────────
function DescriptionModal({ activity, onClose, onEdit, onDelete }) {
  const [mode, setMode] = useState(null);

  if (mode) {
    return (
      <PasswordModal
        onConfirm={() => { mode === 'edit' ? onEdit() : onDelete(); }}
        onCancel={() => setMode(null)}
      />
    );
  }

  return (
    <div className="overlay">
      <div className="modal desc-modal">
        <h2 className="modal-title">Description:</h2>
        <p className="desc-text">{activity.description || <em>No description provided.</em>}</p>
        <div className="btn-row">
          <button className="btn btn-ghost" onClick={onClose}>Close</button>
          <button className="btn btn-warn" onClick={() => setMode('edit')}>Edit</button>
          <button className="btn btn-danger" onClick={() => setMode('delete')}>Delete</button>
        </div>
      </div>
    </div>
  );
}

// ── Cancel Confirm Modal ──────────────────────────────────────────────────────
function CancelConfirmModal({ onConfirm, onKeepEditing }) {
  return (
    <div className="overlay">
      <div className="modal small-modal">
        <h2>Are you sure?</h2>
        <p className="sub-text">This activity will be logged as <strong>Cancelled</strong> and the timer will be reverted.</p>
        <div className="btn-row">
          <button className="btn btn-ghost" onClick={onKeepEditing}>Keep Editing</button>
          <button className="btn btn-danger" onClick={onConfirm}>Confirm</button>
        </div>
      </div>
    </div>
  );
}

// ── helpers for HH:MM:SS input ────────────────────────────────────────────────
const secsToHMS = (s) => {
  const abs = Math.abs(Math.round(s));
  return {
    h: Math.floor(abs / 3600).toString().padStart(2, '0'),
    m: Math.floor((abs % 3600) / 60).toString().padStart(2, '0'),
    s: (abs % 60).toString().padStart(2, '0'),
  };
};
const hmsToSecs = (h, m, s) =>
  (parseInt(h, 10) || 0) * 3600 + (parseInt(m, 10) || 0) * 60 + (parseInt(s, 10) || 0);

// ── Activity Created Modal ────────────────────────────────────────────────────
// manualMode = true  → "Log New Activity" button: all fields editable, no cancel path
// manualMode = false → timer-pause path: time/date come from the pause moment
function ActivityModal({ timeUsedSecs, startedAt, onLog, onCancel, manualMode = false }) {
  const [name, setName] = useState('');
  const [desc, setDesc] = useState('');
  const [showCancelConfirm, setShowCancelConfirm] = useState(false);

  // editable time-used fields
  const initHMS = secsToHMS(timeUsedSecs ?? 0);
  const [th, setTh] = useState(manualMode ? '00' : initHMS.h);
  const [tm, setTm] = useState(manualMode ? '00' : initHMS.m);
  const [ts, setTs] = useState(manualMode ? '00' : initHMS.s);

  // editable date / time fields
  const fallback = startedAt || nowLabel();
  const [dateVal, setDateVal] = useState(manualMode ? '' : fallback.date);
  const [timeVal, setTimeVal] = useState(manualMode ? '' : fallback.time);

  const computedSecs = hmsToSecs(th, tm, ts);
  const timeUsed = formatTime(computedSecs);

  const buildPayload = () => ({
    name,
    description: desc,
    timeUsedSecs: computedSecs,
    dateCreated: dateVal || nowLabel().date,
    timeCreated: timeVal || nowLabel().time,
  });

  if (showCancelConfirm) {
    return (
      <CancelConfirmModal
        onConfirm={() => onCancel(buildPayload())}
        onKeepEditing={() => setShowCancelConfirm(false)}
      />
    );
  }

  return (
    <div className="overlay">
      <div className="modal activity-modal">
        <div className="modal-header-row">
          <h2 className="modal-title">{manualMode ? 'Log New Activity' : 'Activity Created'}</h2>
        </div>

        {/* Time Used — always editable */}
        <label className="field-label">Time Used (HH : MM : SS):</label>
        <div className="hms-row">
          <input className="text-input hms-input" maxLength={2} value={th}
            onChange={e => setTh(e.target.value.replace(/\D/g,'').slice(0,2))}
            placeholder="HH" />
          <span className="hms-sep">:</span>
          <input className="text-input hms-input" maxLength={2} value={tm}
            onChange={e => setTm(e.target.value.replace(/\D/g,'').slice(0,2))}
            placeholder="MM" />
          <span className="hms-sep">:</span>
          <input className="text-input hms-input" maxLength={2} value={ts}
            onChange={e => setTs(e.target.value.replace(/\D/g,'').slice(0,2))}
            placeholder="SS" />
          <span className="hms-preview">{timeUsed.neg ? '-' : ''}{timeUsed.str}</span>
        </div>

        {/* Date / Time — always editable */}
        <div className="date-time-row">
          <div className="date-time-field">
            <label className="field-label">Date Created:</label>
            <input className="text-input" value={dateVal}
              onChange={e => setDateVal(e.target.value)}
              placeholder="e.g. May 8, 2026" />
          </div>
          <div className="date-time-field">
            <label className="field-label">Time Created:</label>
            <input className="text-input" value={timeVal}
              onChange={e => setTimeVal(e.target.value)}
              placeholder="e.g. 03:45:00 PM" />
          </div>
        </div>

        <label className="field-label">Name Activity:</label>
        <input type="text" className="text-input" value={name}
          onChange={e => setName(e.target.value)} placeholder="Give this activity a name…" />
        <label className="field-label">Activity Description:</label>
        <textarea className="text-input textarea" value={desc}
          onChange={e => setDesc(e.target.value)}
          placeholder="Describe what you did together…" rows={5} />
        <div className="btn-row">
          {!manualMode && (
            <button className="btn btn-warn" onClick={() => setShowCancelConfirm(true)}>
              Cancel Activity
            </button>
          )}
          {manualMode && (
            <button className="btn btn-ghost" onClick={() => onCancel(buildPayload())}>
              Close
            </button>
          )}
          <button className="btn btn-success" onClick={() => onLog(buildPayload())}>
            Log Activity
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Edit Activity Modal ───────────────────────────────────────────────────────
function EditActivityModal({ activity, onSave, onClose }) {
  const [name, setName] = useState(activity.name);
  const [desc, setDesc] = useState(activity.description || '');
  const [logged, setLogged] = useState(activity.logged);
  const [showCancelConfirm, setShowCancelConfirm] = useState(false);
  const [dateCreated, setDateCreated] = useState(activity.dateCreated || '');
  const [timeCreated, setTimeCreated] = useState(activity.timeCreated || '');

  // Editable time-used fields
  const initHMS = secsToHMS(activity.timeUsedSecs ?? 0);
  const [th, setTh] = useState(initHMS.h);
  const [tm, setTm] = useState(initHMS.m);
  const [ts, setTs] = useState(initHMS.s);
  const computedSecs = hmsToSecs(th, tm, ts);
  const { neg, str } = formatTime(computedSecs);

  if (showCancelConfirm) {
    return (
      <CancelConfirmModal
        onConfirm={() => onSave({ name, description: desc, logged: false, timeUsedSecs: computedSecs, dateCreated, timeCreated })}
        onKeepEditing={() => setShowCancelConfirm(false)}
      />
    );
  }

  return (
    <div className="overlay">
      <div className="modal activity-modal">
        <div className="modal-header-row">
          <h2 className="modal-title">Edit Activity</h2>
        </div>

        {/* Editable Time Used */}
        <label className="field-label">Time Used (HH : MM : SS):</label>
        <div className="hms-row">
          <input className="text-input hms-input" maxLength={2} value={th}
            onChange={e => setTh(e.target.value.replace(/\D/g,'').slice(0,2))} placeholder="HH" />
          <span className="hms-sep">:</span>
          <input className="text-input hms-input" maxLength={2} value={tm}
            onChange={e => setTm(e.target.value.replace(/\D/g,'').slice(0,2))} placeholder="MM" />
          <span className="hms-sep">:</span>
          <input className="text-input hms-input" maxLength={2} value={ts}
            onChange={e => setTs(e.target.value.replace(/\D/g,'').slice(0,2))} placeholder="SS" />
          <span className="hms-preview">{neg ? '-' : ''}{str}</span>
        </div>

        {/* Editable Date / Time Created */}
        <div className="date-time-row">
          <div className="date-time-field">
            <label className="field-label">Date Created:</label>
            <input className="text-input" value={dateCreated}
              onChange={e => setDateCreated(e.target.value)} placeholder="e.g. May 8, 2026" />
          </div>
          <div className="date-time-field">
            <label className="field-label">Time Created:</label>
            <input className="text-input" value={timeCreated}
              onChange={e => setTimeCreated(e.target.value)} placeholder="e.g. 03:45:00 PM" />
          </div>
        </div>

        <label className="field-label">Name Activity:</label>
        <input type="text" className="text-input" value={name}
          onChange={e => setName(e.target.value)} />
        <label className="field-label">Activity Description:</label>
        <textarea className="text-input textarea" value={desc}
          onChange={e => setDesc(e.target.value)} rows={5} />
        <label className="field-label">Status:</label>
        <div className="toggle-row">
          <button className={`btn btn-sm ${logged ? 'btn-success' : 'btn-ghost'}`}
            onClick={() => setLogged(true)}>Logged</button>
          <button className={`btn btn-sm ${!logged ? 'btn-danger' : 'btn-ghost'}`}
            onClick={() => setLogged(false)}>Cancelled</button>
        </div>
        <div className="btn-row">
          <button className="btn btn-ghost" onClick={onClose}>Discard Changes</button>
          <button className="btn btn-primary"
            onClick={() => onSave({ name, description: desc, logged, timeUsedSecs: computedSecs, dateCreated, timeCreated })}>
            Save Changes
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Main App ──────────────────────────────────────────────────────────────────
export default function App() {
  const [ready, setReady]                 = useState(false);
  const [timerSeconds, setTimerSeconds]   = useState(INITIAL_SECONDS);
  const [running, setRunning]             = useState(false);
  const [activities, setActivities]       = useState([]);
  const [activityModal, setActivityModal] = useState(null);
  const [manualActivityModal, setManualActivityModal] = useState(false);
  const [doneModal, setDoneModal]         = useState(false); // "Done with activity?" prompt
  const [descModal, setDescModal]         = useState(null);
  const [editModal, setEditModal]         = useState(null);
  const [flashRed, setFlashRed]           = useState(false);
  const [blockedModal, setBlockedModal]   = useState(false);
  const [pendingActivity, setPendingActivity] = useState(null);

  // Raw Firebase timer state — read by the local display tick
  const timerStateRef = useRef({ secondsAtStart: INITIAL_SECONDS, startedAt: null, running: false });

  // ── Auth ─────────────────────────────────────────────────────────────────
  useEffect(() => {
    signInAnon().then(() => setReady(true)).catch(console.error);
  }, []);

  // ── Firebase listeners ────────────────────────────────────────────────────
  useEffect(() => {
    if (!ready) return;

    const unsubState = onValue(ref(db, 'timerState'), snap => {
      const val = snap.val();
      if (!val) return;
      timerStateRef.current = val;
      setRunning(!!val.running);
    });

    const unsubActs = onValue(ref(db, 'activities'), snap => {
      const val = snap.val();
      if (val) {
        const list = Object.entries(val).map(([id, a]) => ({ id, ...a }));
        list.sort((a, b) => a.createdAt - b.createdAt);
        setActivities(list);
      } else {
        setActivities([]);
      }
    });

    const unsubPending = onValue(ref(db, 'pendingActivity'), snap => {
      const val = snap.val() || null;
      setPendingActivity(val);
    });

    return () => { unsubState(); unsubActs(); unsubPending(); };
  }, [ready]);

  // ── Local display tick — READS only, never writes ─────────────────────────
  useEffect(() => {
    const tick = () => {
      const { secondsAtStart, startedAt, running: r } = timerStateRef.current;
      if (r && startedAt) {
        const elapsed   = (Date.now() - startedAt) / 1000;
        const displayed = secondsAtStart - elapsed;
        setTimerSeconds(displayed);
        setFlashRed(displayed < 0);
      } else {
        setTimerSeconds(secondsAtStart ?? INITIAL_SECONDS);
        setFlashRed(false);
      }
    };
    tick();
    const id = setInterval(tick, 250);
    return () => clearInterval(id);
  }, [ready]);

  // ── Start ─────────────────────────────────────────────────────────────────
  const handleStart = useCallback(async () => {
    const pendSnap = await get(ref(db, 'pendingActivity'));
    if (pendSnap.val()) {
      setBlockedModal(true);
      return;
    }
    const stateSnap = await get(ref(db, 'timerState'));
    const state     = stateSnap.val() || {};
    const secondsNow = state.running
      ? state.secondsAtStart - (Date.now() - state.startedAt) / 1000
      : (state.secondsAtStart ?? INITIAL_SECONDS);

    await set(ref(db, 'timerState'), {
      secondsAtStart: secondsNow,
      startedAt:      Date.now(),
      running:        true,
    });
  }, []);

  // ── Pause — first ask "Done with activity?" ───────────────────────────────
  const handlePause = useCallback(() => {
    setDoneModal(true);
  }, []);

  // ── User said "Yes" on Done modal — actually pause + open activity form ───
  const handleDoneYes = useCallback(async () => {
    setDoneModal(false);
    const stateSnap = await get(ref(db, 'timerState'));
    const state     = stateSnap.val() || {};
    const currentSeconds = state.running
      ? state.secondsAtStart - (Date.now() - state.startedAt) / 1000
      : (state.secondsAtStart ?? INITIAL_SECONDS);

    // Freeze the timer
    await set(ref(db, 'timerState'), {
      secondsAtStart: currentSeconds,
      startedAt:      null,
      running:        false,
    });

    // Write lock so other tabs see "activity being created"
    const { date, time } = nowLabel();
    const timeUsedSecs    = (state.secondsAtStart ?? INITIAL_SECONDS) - currentSeconds;
    const timerBeforeStart = state.secondsAtStart ?? INITIAL_SECONDS;
    await set(ref(db, 'pendingActivity'), {
      timeUsedSecs,
      timerBeforeStart,
      pausedDate: date,
      pausedTime: time,
    });

    // Open modal directly on this tab — avoids the listener race condition
    setActivityModal({ timeUsedSecs, startedAt: { date, time }, timerBeforeStart });
  }, []);

  // ── User said "No" on Done modal — pause timer silently, no activity form ──
  const handleDoneNo = useCallback(async () => {
    setDoneModal(false);
    const stateSnap = await get(ref(db, 'timerState'));
    const state     = stateSnap.val() || {};
    const currentSeconds = state.running
      ? state.secondsAtStart - (Date.now() - state.startedAt) / 1000
      : (state.secondsAtStart ?? INITIAL_SECONDS);

    await set(ref(db, 'timerState'), {
      secondsAtStart: currentSeconds,
      startedAt:      null,
      running:        false,
    });
  }, []);

  // ── Log Activity ──────────────────────────────────────────────────────────
  const handleLogActivity = useCallback(async (payload) => {
    const pa = pendingActivity;
    // For manual mode (no pendingActivity), just log directly
    if (!pa) {
      await set(ref(db, `activities/${uid()}`), {
        name:         payload.name || 'Untitled',
        description:  payload.description,
        timeUsedSecs: payload.timeUsedSecs,
        dateCreated:  payload.dateCreated || nowLabel().date,
        timeCreated:  payload.timeCreated || nowLabel().time,
        logged:       true,
        createdAt:    Date.now(),
      });
      // Deduct time from timer
      const snap  = await get(ref(db, 'timerState'));
      const state = snap.val() || {};
      const cur   = state.running
        ? state.secondsAtStart - (Date.now() - state.startedAt) / 1000
        : (state.secondsAtStart ?? INITIAL_SECONDS);
      await set(ref(db, 'timerState'), {
        ...state,
        secondsAtStart: cur - payload.timeUsedSecs,
        startedAt: state.running ? Date.now() : null,
      });
      setManualActivityModal(false);
      return;
    }
    await set(ref(db, `activities/${uid()}`), {
      name:         payload.name || 'Untitled',
      description:  payload.description,
      timeUsedSecs: payload.timeUsedSecs ?? pa.timeUsedSecs,
      dateCreated:  payload.dateCreated  || pa.pausedDate,
      timeCreated:  payload.timeCreated  || pa.pausedTime,
      logged:       true,
      createdAt:    Date.now(),
    });
    // If user changed timeUsedSecs vs what was deducted at pause, reconcile
    const diff = (payload.timeUsedSecs ?? pa.timeUsedSecs) - pa.timeUsedSecs;
    if (diff !== 0) {
      const snap  = await get(ref(db, 'timerState'));
      const state = snap.val() || {};
      const cur   = state.running
        ? state.secondsAtStart - (Date.now() - state.startedAt) / 1000
        : (state.secondsAtStart ?? INITIAL_SECONDS);
      await set(ref(db, 'timerState'), {
        ...state,
        secondsAtStart: cur - diff,
        startedAt: state.running ? Date.now() : null,
      });
    }
    await set(ref(db, 'pendingActivity'), null);
    setActivityModal(null);
  }, [pendingActivity]);

  // ── Cancel Activity ───────────────────────────────────────────────────────
  const handleCancelActivity = useCallback(async (payload) => {
    const pa = pendingActivity;
    if (!pa) { setManualActivityModal(false); return; }
    await set(ref(db, `activities/${uid()}`), {
      name:         payload.name || 'Untitled',
      description:  payload.description,
      timeUsedSecs: payload.timeUsedSecs ?? pa.timeUsedSecs,
      dateCreated:  payload.dateCreated  || pa.pausedDate,
      timeCreated:  payload.timeCreated  || pa.pausedTime,
      logged:       false,
      createdAt:    Date.now(),
    });
    // Revert timer
    await set(ref(db, 'timerState'), {
      secondsAtStart: pa.timerBeforeStart,
      startedAt:      null,
      running:        false,
    });
    await set(ref(db, 'pendingActivity'), null);
    setActivityModal(null);
  }, [pendingActivity]);

  // ── Override (force-dismiss pending activity from another tab) ────────────
  const handleOverride = useCallback(async () => {
    const pa = pendingActivity;
    if (pa) {
      // Log as cancelled with a generic name
      await set(ref(db, `activities/${uid()}`), {
        name:         'Overridden Activity',
        description:  '',
        timeUsedSecs: pa.timeUsedSecs,
        dateCreated:  pa.pausedDate,
        timeCreated:  pa.pausedTime,
        logged:       false,
        createdAt:    Date.now(),
      });
      // Revert timer to before the overridden session
      await set(ref(db, 'timerState'), {
        secondsAtStart: pa.timerBeforeStart,
        startedAt:      null,
        running:        false,
      });
      await set(ref(db, 'pendingActivity'), null);
    }
    setActivityModal(null);
    setBlockedModal(false);
  }, [pendingActivity]);

  // ── Edit Activity ─────────────────────────────────────────────────────────
  const handleEditActivity = useCallback((activity) => {
    setDescModal(null);
    setEditModal(activity);
  }, []);

  const handleSaveEdit = useCallback(async ({ name, description, logged, timeUsedSecs: newSecs, dateCreated, timeCreated }) => {
    const original  = editModal;
    const wasLogged = original.logged;
    const oldSecs   = original.timeUsedSecs;
    const updated   = { ...original, name, description, logged, timeUsedSecs: newSecs, dateCreated, timeCreated };
    delete updated.id;
    await set(ref(db, `activities/${original.id}`), updated);

    const snap  = await get(ref(db, 'timerState'));
    const state = snap.val() || {};
    const cur   = state.running
      ? state.secondsAtStart - (Date.now() - state.startedAt) / 1000
      : (state.secondsAtStart ?? INITIAL_SECONDS);

    // Figure out net timer adjustment:
    // If was logged: old secs were deducted. If now logged: new secs should be deducted.
    // delta = what we need to subtract additionally (negative = add back)
    let adjustment = 0;
    if (wasLogged && logged)   adjustment = oldSecs - newSecs; // adjust for changed duration
    if (!wasLogged && logged)  adjustment = -newSecs;          // newly logged → deduct
    if (wasLogged && !logged)  adjustment = oldSecs;           // un-logged → add back

    if (adjustment !== 0) {
      await set(ref(db, 'timerState'), {
        ...state,
        secondsAtStart: cur + adjustment,
        startedAt: state.running ? Date.now() : null,
      });
    }
    setEditModal(null);
  }, [editModal]);

  // ── Delete Activity ───────────────────────────────────────────────────────
  const handleDeleteActivity = useCallback(async (activity) => {
    await set(ref(db, `activities/${activity.id}`), null);
    if (activity.logged) {
      const snap  = await get(ref(db, 'timerState'));
      const state = snap.val() || {};
      const cur   = state.running
        ? state.secondsAtStart - (Date.now() - state.startedAt) / 1000
        : (state.secondsAtStart ?? INITIAL_SECONDS);
      await set(ref(db, 'timerState'), {
        ...state, secondsAtStart: cur + activity.timeUsedSecs,
        startedAt: state.running ? Date.now() : null,
      });
    }
    setDescModal(null);
  }, []);

  // ── Derived ───────────────────────────────────────────────────────────────
  const lastActivityLogged =
    activities.length > 0 &&
    activities[activities.length - 1]?.logged === true &&
    timerSeconds <= 0;

  const { neg, str: timeStr } = formatTime(timerSeconds);

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <div className={`app${flashRed ? ' flash-red' : ''}`}>
      <div className="stars" aria-hidden />

      <header className="hero">
        <div className="confetti-strip" aria-hidden>
          {['🎂','🎉','🎈','✨','🎊','🥳','🎁','🎀','🎂','🎉','🎈','✨','🎊','🥳','🎁','🎀'].map((e,i) => (
            <span key={i} className="confetti-emoji" style={{ '--i': i }}>{e}</span>
          ))}
        </div>
        <h1 className="main-title">Nimay's Birthday Gift</h1>
        <p className="subtitle">
          For Nimay's 30th birthday, Nirav is gifting him{' '}
          <strong>30 hours of his time</strong> to be spent on activities together.
        </p>
      </header>

      <section className="timer-section">
        <div className={`timer-display${neg ? ' timer-negative' : ''}`}>
          {neg && <span className="neg-sign">−</span>}
          <span className="timer-digits">{timeStr}</span>
        </div>
        {neg && <p className="overtime-label">⚠ Overtime — Nirav owes Nimay extra time!</p>}

        <div className="timer-controls">
          {running ? (
            <button className="btn btn-pause" onClick={handlePause}>
              ⏸ Pause Timer
            </button>
          ) : (
            <>
              <button
                className={`btn btn-start${lastActivityLogged ? ' btn-disabled' : ''}`}
                onClick={handleStart}
                disabled={lastActivityLogged}
                title={lastActivityLogged ? 'All time has been used and logged.' : ''}
              >
                ▶ Start Timer
              </button>
              <button className="btn btn-new-activity" onClick={() => setManualActivityModal(true)}>
                ✏️ Log New Activity
              </button>
            </>
          )}
        </div>
      </section>

      {activities.length > 0 && (
        <section className="table-section">
          <h2 className="table-heading">Activity Log</h2>
          <div className="table-wrap">
            <table className="activity-table">
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Time Used</th>
                  <th>Date Created</th>
                  <th>Time Created</th>
                  <th>Logged?</th>
                  <th>Description</th>
                </tr>
              </thead>
              <tbody>
                {activities.map(act => {
                  const { neg: n, str: t } = formatTime(act.timeUsedSecs);
                  return (
                    <tr key={act.id} className={act.logged ? 'row-logged' : 'row-cancelled'}>
                      <td className="td-name">{act.name}</td>
                      <td className="td-time">{n ? '-' : ''}{t}</td>
                      <td>{act.dateCreated}</td>
                      <td>{act.timeCreated}</td>
                      <td>
                        <span className={`badge ${act.logged ? 'badge-logged' : 'badge-cancelled'}`}>
                          {act.logged ? 'Logged' : 'Cancelled'}
                        </span>
                      </td>
                      <td>
                        <button className="btn btn-sm btn-show" onClick={() => setDescModal(act)}>
                          Show Description
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </section>
      )}

      {activityModal && !editModal && (
        <ActivityModal
          timeUsedSecs={activityModal.timeUsedSecs}
          startedAt={activityModal.startedAt}
          onLog={handleLogActivity}
          onCancel={handleCancelActivity}
        />
      )}

      {editModal && (
        <EditActivityModal
          activity={editModal}
          onSave={handleSaveEdit}
          onClose={() => setEditModal(null)}
        />
      )}

      {descModal && !editModal && (
        <DescriptionModal
          activity={descModal}
          onClose={() => setDescModal(null)}
          onEdit={() => handleEditActivity(descModal)}
          onDelete={() => handleDeleteActivity(descModal)}
        />
      )}

      {blockedModal && (
        <ActivityBlockedModal
          onClose={() => setBlockedModal(false)}
          onOverride={handleOverride}
        />
      )}

      {/* "Done with activity?" prompt shown when Pause Timer is pressed */}
      {doneModal && (
        <div className="overlay">
          <div className="modal small-modal">
            <h2>Done with activity?</h2>
            <p className="sub-text">
              Choose <strong>Yes</strong> to log this session, or{' '}
              <strong>No</strong> to pause the timer without creating an activity.
            </p>
            <div className="btn-row">
              <button className="btn btn-ghost" onClick={handleDoneNo}>No</button>
              <button className="btn btn-success" onClick={handleDoneYes}>Yes</button>
            </div>
          </div>
        </div>
      )}

      {/* Manual "Log New Activity" modal */}
      {manualActivityModal && (
        <ActivityModal
          timeUsedSecs={0}
          startedAt={null}
          onLog={handleLogActivity}
          onCancel={() => setManualActivityModal(false)}
          manualMode={true}
        />
      )}
    </div>
  );
}
